<script setup lang="ts">
import { computed, reactive, ref, watch } from 'vue'
import { ElMessageBox } from 'element-plus'
import type { InsuranceAttachment, InsuranceCoverages, InsuranceStatusSummary, InsuranceVisibility, TravelInsurance, Trip } from '../types'
import { coverageLabel, validateCoveragePeriod } from '../utils/insuranceCoverage'

const props = defineProps<{ trip: Trip; insurance?: TravelInsurance; statuses: Record<string, InsuranceStatusSummary>; userId: string; memberName: (id: string) => string; canEdit: boolean; saving?: boolean }>()
const emit = defineEmits<{ save: [payload: Omit<TravelInsurance, 'id' | 'createdAt' | 'updatedAt'> & Partial<Pick<TravelInsurance, 'createdAt'>>, files: File[]]; remove: [insurance: TravelInsurance]; openAttachment: [attachment: InsuranceAttachment] }>()
const showForm = ref(false); const uploadFiles = ref<File[]>([])
const blankCoverages = (): InsuranceCoverages => ({ accidentDeath: 0, accidentDisability: 0, overseasMedical: 0, emergencyIllness: 0, emergencyEvacuation: 0, flightDelay: 0, baggageDelay: 0, baggageLoss: 0, tripCancellation: 0, tripChange: 0, personalLiability: 0, legalInfectiousDisease: 0 })
const form = reactive({ providerName: '', policyName: '', policyNumber: '', insuredName: '', coverageStart: '', coverageEnd: '', premiumAmount: 0, premiumCurrency: '', coverages: blankCoverages(), emergencyPhone: '', customerServicePhone: '', claimPhone: '', assistancePhone: '', website: '', note: '', visibility: 'private' as InsuranceVisibility, status: 'draft' as TravelInsurance['status'], attachments: [] as InsuranceAttachment[] })
const coverageFields: [keyof InsuranceCoverages, string][] = [['accidentDeath', '意外身故'], ['accidentDisability', '意外失能'], ['overseasMedical', '海外醫療'], ['emergencyIllness', '突發疾病'], ['emergencyEvacuation', '緊急救援'], ['flightDelay', '班機延誤'], ['baggageDelay', '行李延誤'], ['baggageLoss', '行李遺失'], ['tripCancellation', '旅程取消'], ['tripChange', '旅程更改'], ['personalLiability', '第三人責任'], ['legalInfectiousDisease', '法定傳染病']]
const coverage = computed(() => props.insurance ? validateCoveragePeriod(props.insurance.coverageStartAt, props.insurance.coverageEndAt, props.trip) : null)
const memberRows = computed(() => props.trip.members.map((member) => ({ member, summary: props.statuses[member.id], mine: member.id === props.userId })))
const activeCount = computed(() => Object.values(props.statuses).filter((item) => item.status === 'covered').length)
const policyCoverageItems = computed(() => coverageFields.filter(([key]) => Number(props.insurance?.coverages[key]) > 0).slice(0, 5))
function toInputDate(value?: number) { return value ? new Date(value).toISOString().slice(0, 16) : '' }
function resetForm() { const source = props.insurance; form.providerName = source?.providerName || ''; form.policyName = source?.policyName || ''; form.policyNumber = source?.policyNumber || ''; form.insuredName = source?.insuredName || props.memberName(props.userId); form.coverageStart = toInputDate(source?.coverageStartAt); form.coverageEnd = toInputDate(source?.coverageEndAt); form.premiumAmount = source?.premiumAmount || 0; form.premiumCurrency = source?.premiumCurrency || props.trip.currency; form.coverages = { ...blankCoverages(), ...(source?.coverages || {}) }; form.emergencyPhone = source?.emergencyPhone || ''; form.customerServicePhone = source?.customerServicePhone || ''; form.claimPhone = source?.claimPhone || ''; form.assistancePhone = source?.assistancePhone || ''; form.website = source?.website || ''; form.note = source?.note || ''; form.visibility = source?.visibility || 'private'; form.status = source?.status || 'draft'; form.attachments = [...(source?.attachments || [])]; uploadFiles.value = [] }
function openForm() { resetForm(); showForm.value = true }
function onFiles(event: Event) { const files = Array.from((event.target as HTMLInputElement).files || []); uploadFiles.value.push(...files.filter((file) => file.size <= 10 * 1024 * 1024 && /^(image\/(jpeg|png|webp)|application\/pdf)$/.test(file.type))) }
function removePending(index: number) { uploadFiles.value.splice(index, 1) }
function removeAttachment(index: number) { form.attachments.splice(index, 1) }
function save() { if (!form.providerName.trim() || !form.policyName.trim() || !form.insuredName.trim() || !form.coverageStart || !form.coverageEnd) return; const start = new Date(form.coverageStart).getTime(); const end = new Date(form.coverageEnd).getTime(); if (end < start) return; emit('save', { tripId: props.trip.id, userId: props.userId, providerName: form.providerName.trim(), policyName: form.policyName.trim(), policyNumber: form.policyNumber.trim() || undefined, insuredName: form.insuredName.trim(), coverageStartAt: start, coverageEndAt: end, premiumAmount: Number(form.premiumAmount) || undefined, premiumCurrency: form.premiumCurrency || props.trip.currency, coverages: Object.fromEntries(Object.entries(form.coverages).filter(([, value]) => Number(value) > 0)), emergencyPhone: form.emergencyPhone.trim() || undefined, customerServicePhone: form.customerServicePhone.trim() || undefined, claimPhone: form.claimPhone.trim() || undefined, assistancePhone: form.assistancePhone.trim() || undefined, website: form.website.trim() || undefined, note: form.note.trim() || undefined, attachments: form.attachments, visibility: form.visibility, status: form.status, createdBy: props.insurance?.createdBy || props.userId, createdAt: props.insurance?.createdAt }, uploadFiles.value); showForm.value = false }
async function removePolicy() { if (!props.insurance) return; try { await ElMessageBox.confirm('確定要刪除自己的保險資料嗎？附件也會從資料庫移除。', '刪除保單', { type: 'warning', confirmButtonText: '刪除', cancelButtonText: '取消' }); emit('remove', props.insurance) } catch { /* cancelled */ } }
watch(() => props.insurance, resetForm, { immediate: true })
</script>

<template>
  <section class="insurance-card panel">
    <header class="insurance-heading"><div><p>INSURANCE</p><h2>旅行保險與緊急資訊</h2><span>集中保管自己的保單、保障期間與緊急聯絡方式。</span></div><el-button v-if="canEdit" type="primary" class="insurance-add" @click="openForm">＋ {{ insurance ? '編輯我的保單' : '新增保單' }}</el-button></header>
    <div class="insurance-summary"><article><span>旅行成員</span><strong>{{ trip.members.length }} 人</strong></article><article><span>已提供保單</span><strong>{{ Object.keys(statuses).length }} 人</strong></article><article><span>保障完整</span><strong>{{ activeCount }} 人</strong></article><article><span>保障缺口</span><strong class="warning">{{ Object.values(statuses).filter((item) => item.status === 'coverage_gap').length }} 人</strong></article></div>
    <div v-if="insurance" class="insurance-policy">
      <div class="insurance-policy-top"><div><span :class="['insurance-status', `is-${coverage}`]">{{ coverage ? coverageLabel[coverage] : '尚未檢查' }}</span><h3>{{ insurance.policyName }}</h3><p>{{ insurance.providerName }} · {{ insurance.insuredName }}</p></div><el-dropdown trigger="click"><button class="insurance-more" type="button" aria-label="保單更多操作">⋯</button><template #dropdown><el-dropdown-menu><el-dropdown-item @click="openForm">編輯保單</el-dropdown-item><el-dropdown-item divided class="danger-action" @click="removePolicy">刪除保單</el-dropdown-item></el-dropdown-menu></template></el-dropdown></div>
      <p class="insurance-period">保障期間 {{ new Date(insurance.coverageStartAt).toLocaleString('zh-TW') }}－{{ new Date(insurance.coverageEndAt).toLocaleString('zh-TW') }}</p>
      <div class="insurance-coverages"><span v-for="([key, label]) in policyCoverageItems" :key="key">{{ label }} {{ insurance.coverages[key]?.toLocaleString() }}</span><span v-if="!policyCoverageItems.length">尚未填寫保障額度</span></div>
      <div v-if="insurance.emergencyPhone || insurance.customerServicePhone || insurance.claimPhone || insurance.assistancePhone" class="insurance-phones"><a v-if="insurance.emergencyPhone" :href="`tel:${insurance.emergencyPhone}`">緊急救援 {{ insurance.emergencyPhone }}</a><a v-if="insurance.customerServicePhone" :href="`tel:${insurance.customerServicePhone}`">客服 {{ insurance.customerServicePhone }}</a><a v-if="insurance.claimPhone" :href="`tel:${insurance.claimPhone}`">理賠 {{ insurance.claimPhone }}</a><a v-if="insurance.assistancePhone" :href="`tel:${insurance.assistancePhone}`">旅遊協助 {{ insurance.assistancePhone }}</a></div>
      <div v-if="insurance.attachments?.length" class="insurance-attachments"><button v-for="attachment in insurance.attachments || []" :key="attachment.secureUrl" type="button" @click="emit('openAttachment', attachment)">📎 {{ attachment.originalFilename || '保單附件' }}</button></div>
    </div>
    <div v-else class="insurance-empty"><span>🛡</span><strong>尚未建立你的保險資料</strong><p>保單與緊急聯絡資訊只會依你的可見性設定分享。</p><el-button v-if="canEdit" @click="openForm">新增我的保單</el-button></div>
    <div class="insurance-members"><h3>成員保險狀態</h3><div v-for="row in memberRows" :key="row.member.id" class="insurance-member"><span class="insurance-avatar">{{ row.member.name.slice(0, 1) }}</span><div><strong>{{ row.member.name }} <small v-if="row.mine">（我）</small></strong><span>{{ row.summary?.providerName || (row.summary ? '已提供保單' : '尚未提供') }}</span></div><b :class="`member-status is-${row.summary?.status || 'not_provided'}`">{{ row.summary?.status === 'covered' ? '保障完整' : row.summary?.status === 'coverage_gap' ? '保障不足' : row.summary?.status === 'draft' ? '草稿' : row.summary?.status === 'expired' ? '已過期' : row.summary?.status === 'cancelled' ? '已取消' : '尚未提供' }}</b></div></div>
  </section>
  <el-dialog v-model="showForm" class="insurance-dialog" :title="insurance ? '編輯我的保單' : '新增我的保單'" width="min(94vw, 760px)" destroy-on-close>
    <el-form label-position="top"><div class="insurance-form-grid"><el-form-item label="保險公司" required><el-input v-model="form.providerName" placeholder="例如：國泰產險" /></el-form-item><el-form-item label="保單名稱" required><el-input v-model="form.policyName" placeholder="例如：海外旅遊綜合保險" /></el-form-item><el-form-item label="保單號碼（選填）"><el-input v-model="form.policyNumber" /></el-form-item><el-form-item label="被保險人" required><el-input v-model="form.insuredName" /></el-form-item><el-form-item label="保費（選填）"><el-input-number v-model="form.premiumAmount" :min="0" controls-position="right" /></el-form-item><el-form-item label="幣別"><el-select v-model="form.premiumCurrency"><el-option :label="trip.currency" :value="trip.currency" /><el-option label="TWD" value="TWD" /><el-option label="JPY" value="JPY" /><el-option label="USD" value="USD" /></el-select></el-form-item><el-form-item label="保障開始" required><el-date-picker v-model="form.coverageStart" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss" /></el-form-item><el-form-item label="保障結束" required><el-date-picker v-model="form.coverageEnd" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss" /></el-form-item></div><el-form-item label="可見性"><el-radio-group v-model="form.visibility"><el-radio-button label="private">僅自己（其他人只見狀態）</el-radio-button><el-radio-button label="status_only">狀態與保險公司</el-radio-button><el-radio-button label="trip_members">旅行成員可查看</el-radio-button></el-radio-group></el-form-item><el-form-item label="保單狀態"><el-radio-group v-model="form.status"><el-radio-button label="draft">草稿</el-radio-button><el-radio-button label="active">生效中</el-radio-button><el-radio-button label="cancelled">已取消</el-radio-button></el-radio-group></el-form-item><h3 class="insurance-form-subtitle">主要保障額度</h3><div class="insurance-coverage-grid"><el-form-item v-for="([key, label]) in coverageFields" :key="key" :label="label"><el-input-number v-model="form.coverages[key]" :min="0" controls-position="right" /></el-form-item></div><h3 class="insurance-form-subtitle">緊急聯絡資訊</h3><div class="insurance-form-grid"><el-form-item label="緊急救援電話"><el-input v-model="form.emergencyPhone" inputmode="tel" /></el-form-item><el-form-item label="客服電話"><el-input v-model="form.customerServicePhone" inputmode="tel" /></el-form-item><el-form-item label="理賠電話"><el-input v-model="form.claimPhone" inputmode="tel" /></el-form-item><el-form-item label="旅遊協助電話"><el-input v-model="form.assistancePhone" inputmode="tel" /></el-form-item></div><el-form-item label="保險網站"><el-input v-model="form.website" placeholder="https://" /></el-form-item><el-form-item label="備註"><el-input v-model="form.note" type="textarea" maxlength="500" show-word-limit /></el-form-item><el-form-item label="保單附件（JPG、PNG、WebP、PDF；單檔 10 MB）"><input type="file" accept="image/jpeg,image/png,image/webp,application/pdf" multiple @change="onFiles" /><div v-if="form.attachments.length || uploadFiles.length" class="insurance-file-list"><span v-for="(attachment, index) in form.attachments" :key="attachment.secureUrl">{{ attachment.originalFilename || '已上傳附件' }} <button type="button" @click="removeAttachment(index)">移除</button></span><span v-for="(file, index) in uploadFiles" :key="`${file.name}-${index}`">{{ file.name }} <button type="button" @click="removePending(index)">移除</button></span></div></el-form-item></el-form>
    <template #footer><el-button :disabled="saving" @click="showForm=false">取消</el-button><el-button type="primary" :loading="saving" @click="save">儲存保單</el-button></template>
  </el-dialog>
</template>

<style scoped>
.insurance-card{grid-column:1/-1;padding:24px}.insurance-heading{display:flex;align-items:start;justify-content:space-between;gap:18px;padding-bottom:18px;border-bottom:1px solid #e6ece8}.insurance-heading p{margin:0;color:#de765e;font-size:11px;font-weight:800;letter-spacing:1.2px}.insurance-heading h2{margin:3px 0;color:#163b37;font-size:20px}.insurance-heading span{color:#6b7d78;font-size:13px}.insurance-add{min-height:42px;border:0;background:#123f3a}.insurance-summary{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;margin:18px 0}.insurance-summary article{display:grid;gap:4px;padding:12px;border:1px solid #e1e8e3;border-radius:12px;background:#fbfcfa}.insurance-summary span{color:#6b7d78;font-size:12px}.insurance-summary strong{color:#163b37;font-size:17px}.insurance-summary .warning{color:#bd7a1d}.insurance-policy{display:grid;gap:12px;padding:16px;border:1px solid #bcdacf;border-radius:14px;background:#f7fbf8}.insurance-policy-top{display:flex;justify-content:space-between;gap:12px}.insurance-status{display:inline-flex;padding:3px 7px;border-radius:999px;background:#e9f5ee;color:#28725f;font-size:11px;font-weight:800}.insurance-status.is-starts_late,.insurance-status.is-ends_early,.insurance-status.is-outside_trip{background:#fff4d9;color:#956315}.insurance-status.is-expired,.insurance-status.is-invalid{background:#fdecea;color:#ba554d}.insurance-policy h3{margin:7px 0 2px;color:#163b37;font-size:17px}.insurance-policy p{margin:0;color:#6b7d78;font-size:13px}.insurance-more{width:36px;height:36px;border:0;border-radius:9px;background:transparent;color:#53736a;font-size:20px;cursor:pointer}.insurance-more:hover{background:#e6f0eb}.insurance-period{line-height:1.5}.insurance-coverages,.insurance-phones,.insurance-attachments{display:flex;flex-wrap:wrap;gap:7px}.insurance-coverages span{padding:4px 8px;border-radius:8px;background:#e9f4ef;color:#396b5e;font-size:12px}.insurance-phones a,.insurance-attachments a{padding:6px 8px;border:1px solid #d4e5dc;border-radius:8px;color:#216b59;font-size:12px;text-decoration:none}.insurance-empty{display:grid;justify-items:center;gap:7px;margin:18px 0;padding:30px;border:1px dashed #c9ddd4;border-radius:14px;text-align:center}.insurance-empty span{font-size:28px}.insurance-empty strong{color:#244a43}.insurance-empty p{margin:0;color:#6b7d78;font-size:13px}.insurance-members{margin-top:22px}.insurance-members h3{margin:0 0 8px;color:#244a43;font-size:15px}.insurance-member{display:grid;grid-template-columns:36px minmax(0,1fr) auto;gap:10px;align-items:center;padding:10px 4px;border-bottom:1px solid #edf1ef}.insurance-avatar{display:grid;width:34px;height:34px;place-items:center;border-radius:50%;background:#e5f2ec;color:#276a59;font-size:13px;font-weight:800}.insurance-member div{display:grid;gap:2px;min-width:0}.insurance-member strong{color:#244a43;font-size:14px}.insurance-member strong small,.insurance-member span{color:#71827c;font-size:12px}.member-status{padding:4px 8px;border-radius:999px;background:#f1f3f2;color:#78847f;font-size:11px;white-space:nowrap}.member-status.is-covered{background:#e8f5ed;color:#28735e}.member-status.is-coverage_gap{background:#fff4d9;color:#966319}.member-status.is-expired,.member-status.is-cancelled{background:#fdecea;color:#b9564e}.insurance-form-grid,.insurance-coverage-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:0 14px}.insurance-coverage-grid{grid-template-columns:repeat(3,minmax(0,1fr))}.insurance-dialog .el-date-editor,.insurance-dialog .el-input-number,.insurance-dialog .el-select{width:100%}.insurance-form-subtitle{margin:8px 0 12px;color:#244a43;font-size:15px}.insurance-file-list{display:grid;gap:5px;margin-top:8px}.insurance-file-list span{display:flex;justify-content:space-between;gap:10px;padding:6px 8px;border-radius:7px;background:#f2f7f4;color:#52736a;font-size:12px}.insurance-file-list button{border:0;background:transparent;color:#b8564f;cursor:pointer}@media(max-width:600px){.insurance-card{padding:16px}.insurance-heading{align-items:stretch;flex-direction:column}.insurance-add{width:100%}.insurance-summary{grid-template-columns:repeat(2,minmax(0,1fr));gap:8px}.insurance-form-grid,.insurance-coverage-grid{grid-template-columns:1fr}.insurance-member{grid-template-columns:34px minmax(0,1fr)}.member-status{grid-column:2;justify-self:start}.insurance-policy{padding:12px}}
</style>
